function addEventListenerForTouch(){let touchStartTime=0;let touchStartX=0;let touchStartY=0;const pressThreshold=400;const moveThreshold=10;document.addEventListener("touchstart",function(event){touchStartTime=Date.now();touchStartX=event.touches[0].clientX;touchStartY=event.touches[0].clientY});let pendingTouchUpTimeout=null;let pendingTouchUpHandler=null;document.addEventListener("touchend",function(event){const duration=Date.now()-touchStartTime;const touch=event.changedTouches[0];const touchEndX=touch.clientX;const touchEndY=touch.clientY;const distanceX=Math.abs(touchEndX-touchStartX);const distanceY=Math.abs(touchEndY-touchStartY);if(duration<pressThreshold&&distanceX<moveThreshold&&distanceY<moveThreshold){if(!isLinkMediaActionAtPoint(touchEndX,touchEndY)){const handler=findTouchUpHandlerAtPoint(touchEndX,touchEndY);if(handler){pendingTouchUpHandler=()=>handler(touch);pendingTouchUpTimeout=setTimeout(()=>{pendingTouchUpHandler();pendingTouchUpHandler=null;pendingTouchUpTimeout=null},100)}}}});document.addEventListener("click",function(event){if(pendingTouchUpTimeout){clearTimeout(pendingTouchUpTimeout);pendingTouchUpTimeout=null}const closestAnchor=event.target.closest("a");let isValidHref=false;if(closestAnchor&&closestAnchor.href){try{new URL(closestAnchor.href);isValidHref=true}catch(e){}}if(!isValidHref){if(pendingTouchUpHandler){pendingTouchUpHandler()}}pendingTouchUpHandler=null})}function isWebViewTapAtPoint(x,y){const selection=window.getSelection();if(selection&&!selection.isCollapsed&&selection.rangeCount>0){return true}if(isLinkMediaActionAtPoint(x,y)){return true}if(findTouchUpHandlerAtPoint(x,y)!==null){return true}return false}function isLinkMediaActionAtPoint(x,y){const element=document.elementFromPoint(x,y);if(!element){return false}const strictLink=element.closest("a");if(strictLink&&strictLink.href&&strictLink.href.length>0){return true}const tolerance=5;const childLinks=element.getElementsByTagName("a");for(let i=0;i<childLinks.length;i++){const link=childLinks[i];const rect=link.getBoundingClientRect();if(x>=rect.left-tolerance&&x<=rect.right+tolerance&&y>=rect.top-tolerance&&y<=rect.bottom+tolerance){if(link.href&&link.href.length>0){return true}}}if(element instanceof HTMLMediaElement||element.closest("video, audio")){return true}if(willTapTriggerEpubAction(element)){return true}return false}function willTapTriggerEpubAction(element){if(!element||!element.id){return false}const elementId=element.id;const selector=`epub\\:trigger[ev\\:observer="${elementId}"]`;const matchingTrigger=document.querySelector(selector);return!!matchingTrigger}const touchUpHandlerStore=[];function registerTouchUpHandler(element,handler){if(!(element instanceof HTMLElement)){return}if(typeof handler!=="function"){return}touchUpHandlerStore.push({element:element,handler:handler})}function unregisterTouchUpHandler(element){const index=touchUpHandlerStore.findIndex(item=>item.element===element);if(index>-1){touchUpHandlerStore.splice(index,1);return true}return false}function findTouchUpHandlerAtPoint(x,y){for(let i=touchUpHandlerStore.length-1;i>=0;i--){const{element,handler}=touchUpHandlerStore[i];const rect=getNonZeroBoundingClientRect(element);const isInside=x>=rect.left&&x<=rect.right&&y>=rect.top&&y<=rect.bottom;if(isInside){return handler}}return null}